When building production-ready Django applications, writing robust unit tests is non-negotiable. A well-structured unit testing strategy ensures:Changes don’t break existing functionality.Business logic works as expected.You have confidence in refactoring.
This guide walks through how to write scalable unit tests using a structured and reusable pattern—complete with mock data, a shared test base, map factories, and advanced mocking techniques like MagicMock and @patch.


  Project Test Structure Overview
Let’s use a modular and DRY (Don’t Repeat Yourself) structure for our Django test suite:your_project/
├── base_test/
│   ├── base_map_factory.py
│   ├── constant_model_map.py
│   └── base_test_case.py
├── your_app/
│   │   ├── maps/
│   │   │   └── merchant_map.py
│   │   └── test_send_key_salt.py


  🔧 1. Base Map Factory — Reusable Test Data Provider
📁 base_test/base_map_factory.pyimport copy

class BaseMapFactory:
    def __init__(self, map=None):
        self.map = map or {}
    def get_map(self, key=None, updates={}):
        try:
            data = self.map
            for k in key:
                data = copy.deepcopy(data[k])
            if updates:
                if isinstance(data, list):
                    for item in data:
                        item.update(updates)
                elif isinstance(data, dict):
                    data.update(updates)
            return data
        except (KeyError, TypeError) as e:
            print("Error fetching map:", e)
            return None
Encapsulates test data in an extendable pattern.Prevents mutation of original data.Enables easy overrides using updates.


  2. Constant Test Data for DB Models
📁 base_test/constant_model_map.pyfrom base_test.base_map_factory import BaseMapFactory

class ConstantModelMap(BaseMapFactory):
    def __init__(self):
        self.map = {
            "merchant_credentials": {
                "id": 1,
                "merchant_id": "EXAMPLE123",
                "api_key": "secureapikey",
                "callback_url": "https://callback.test.com"
            },
            "merchant_info": {
                "merchant_id": 123,
                "merchant_name": "Test Merchant",
                "email": "merchant@example.com"
            }
        }
        super().__init__(self.map)
Maintains a single source of truth for model test data.Easy to maintain and change without digging into tests.


  🧪 3. Shared Base Test Case
📁 base_test/base_test_case.pyfrom django.test import TestCase, Client
from base_test.constant_model_map import ConstantModelMap
from your_app.models import Merchant, MerchantCredentials

class BaseDjangoTestCase(TestCase):
    @classmethod
    def setUpClass(cls):
        super().setUpClass()
        cls.client = Client()
        cls.models_map = ConstantModelMap()

        cls.merchant = Merchant.objects.create(
            **cls.models_map.get_map(["merchant_info"])
        )
        cls.credentials = MerchantCredentials.objects.create(
            **cls.models_map.get_map(["merchant_credentials"])
        )

Promotes code reuse across test files.Sets up test models in a shared, structured way.


  💼 4. Map for Service/API-Specific Static Data
📁 your_app/tests/maps/merchant_map.pyfrom base_test.base_map_factory import BaseMapFactory

class MerchantTestMap(BaseMapFactory):
    def __init__(self):
        self.map = {
            "common_request_data": {
                "merchant_id": 123,
                "key": "value"
            },
            "successful_response": {
                "status": "success",
                "data": {"message": "Key sent"}
            },
            "error_response": {
                "status": "error",
                "data": {"message": "Invalid merchant_id"}
            }
        }
        super().__init__(self.map)




  🚀 5. Test File — Using All the Building Blocks
📁 your_app/tests/test_send_key_salt.pyfrom django.urls import reverse
from unittest.mock import patch, MagicMock

from base_test.base_test_case import BaseDjangoTestCase
from your_app.tests.maps.merchant_map import MerchantTestMap
from shared.utility.loggers.logging import AppLogger
from shared.utility.push import Push

class SendKeySaltTests(BaseDjangoTestCase):
    @classmethod
    def setUpClass(cls):
        super().setUpClass()
        cls.endpoint = reverse("send-key-salt")
        cls.map = MerchantTestMap()
        cls.error_prefix = ":: SendKeySaltTests :: "

    @patch.object(AppLogger, "info")
    def test_successful_key_sending(self, mock_info):
        response = self.client.post(self.endpoint, self.map.get_map(["common_request_data"]))
        self.assertEqual(response.status_code, 200)
        self.assertEqual(response.json(), self.map.get_map(["successful_response"]))
        self.assertTrue(mock_info.called)

    @patch.object(AppLogger, "info")
    @patch.object(AppLogger, "exception")
    def test_missing_merchant_id(self, mock_exception, mock_info):
        bad_data = self.map.get_map(["common_request_data"], updates={"merchant_id": ""})
        response = self.client.post(self.endpoint, bad_data)
        self.assertEqual(response.status_code, 400)
        self.assertEqual(response.json(), self.map.get_map(["error_response"]))
        self.assertTrue(mock_exception.called)

    @patch.object(Push, "push_mail")
    def test_push_notification_mock(self, mock_push):
        mock_push.return_value = True
        response = self.client.post(self.endpoint, self.map.get_map(["common_request_data"]))
        self.assertEqual(response.status_code, 200)
        mock_push.assert_called_once()

@patch.object(SomeClass, "method") dynamically replaces a method for the duration of a test.MagicMock is used to create dummy objects or simulate return values.@patch.object(Logger, "info")
def test_logs_info(self, mock_info):
    call_my_view()
    mock_info.assert_called_once()
✅ This avoids real logging and isolates the unit of work.


  A Quick Summary About Packages And Concept
✅ Django Test Framework (django.test)django.test.TestCase: Django’s built-in test class (inherits from Python’s unittest.TestCase).client = Client(): Simulates HTTP requests for views (like POST, GET, PUT).Used for integration-style tests that hit the full Django stack including URLs, middleware, views, etc.patch: A decorator/context manager to replace objects with mocks during tests.MagicMock: A flexible mock object that simulates return values, method calls, etc.Prevent hitting external APIs, file systems, DBs, or logs.Assert if external services like Push.push_mail() or PGLogger.info() were called with correct data.
Example:
@patch.object(PGLogger, "info")
def test_logging(self, mock_log):
view()
assert mock_log.called
Used to create in-memory Excel files in tests for upload scenarios.Workbook(), ws.append(...): Used to mock file content for forms, upload testing.Dynamically builds URLs from view names.Helps you avoid hardcoding endpoint paths, improving test portability.✅ django.core.files.uploadedfile.SimpleUploadedFileUsed to create mock files in memory (text, Excel, PDF).Useful for testing file upload views.Used in BaseMapFactory to return cloned test data and prevent mutation of original test dictionaries.Ensures that get_map(..., updates={}) doesn’t affect future test cases.Investing time in writing clean, isolated, and scalable unit tests pays off enormously in the long run. With a base test case, reusable factory maps, and clever mocking, your Django tests can be as maintainable as your production code.

Today I will show you how to build a tiny x and y tracker in JS
class PositionCounter {
    constructor(x = 0, y = 0) {
        this.x = x;
        this.y = y;
    }

    // Move the position by dx and dy
    move(dx, dy) {
        this.x += dx;
        this.y += dy;
        return this; // Allow method chaining
    }

    // Reset position to (0, 0)
    reset() {
        this.x = 0;
        this.y = 0;
        return this; // Allow method chaining
    }

    // Display current position
    display() {
        console.log(`Current Position: X = ${this.x}, Y = ${this.y}`);
        return this; // Allow method chaining
    }

    // Get current position as an object
    getPosition() {
        return { x: this.x, y: this.y };
    }
}

// Example usage:
const counter = new PositionCounter();

counter.move(5, 3).display();       // Move and display
counter.move(-2, 7).display();      // Move again and display
counter.reset().display();           // Reset and display

// Or get position without displaying:
const currentPos = counter.move(10, 20).getPosition();
console.log('Current position:', currentPos);


<!DOCTYPE html>
<html>
<head>
    <title>Position Counter Demo</title>
    <style>
        body { font-family: Arial, sans-serif; margin: 20px; }
        button { margin: 5px; padding: 8px 12px; }
        #output { margin-top: 20px; padding: 10px; border: 1px solid #ccc; }
    </style>
</head>
<body>
    <h1>Position Counter</h1>
    <div>
        <button onclick="move(1, 0)">Move Right (+X)</button>
        <button onclick="move(-1, 0)">Move Left (-X)</button>
        <button onclick="move(0, 1)">Move Down (+Y)</button>
        <button onclick="move(0, -1)">Move Up (-Y)</button>
        <button onclick="reset()">Reset</button>
    </div>
    <div id="output">Position: X=0, Y=0</div>

    <script>
        const counter = new PositionCounter();
        const output = document.getElementById('output');

        function updateDisplay() {
            output.textContent = `Position: X=${counter.x}, Y=${counter.y}`;
        }

        function move(dx, dy) {
            counter.move(dx, dy);
            updateDisplay();
        }

        function reset() {
            counter.reset();
            updateDisplay();
        }

        // The PositionCounter class from above would go here
        class PositionCounter {
            constructor(x = 0, y = 0) {
                this.x = x;
                this.y = y;
            }

            move(dx, dy) {
                this.x += dx;
                this.y += dy;
                return this;
            }

            reset() {
                this.x = 0;
                this.y = 0;
                return this;
            }
        }
    </script>
</body>
</html>

Welcome to  of our FastAPI journey! Yesterday, we explored how to use Request Bodies and Pydantic to validate data like a pro.Today, we step into the powerful world of  — and why FastAPI’s  makes our code cleaner, reusable, and more secure.


  🧠 What Is Dependency Injection (DI)?
Imagine you're building an app where every route requires , or , or even a .Instead of repeating the same logic in every route, you can  it once using  — and FastAPI handles it for you!


  🎯 Real-World Analogy:  is Your Personal Assistant
Let’s say you run a restaurant. Instead of you greeting customers, validating reservations, and serving them every time…You  those tasks to trusted staff — that’s Dependency Injection!Your function = the restaurantThe  function = your assistant (API key checker, paginator, etc.)FastAPI = your efficient manager


  🔧 Step-by-Step: Basic Dependency Injection



  📁 Create a file called from fastapi import FastAPI, Depends

app = FastAPI()

# Step 1: Create a dependency function
def say_hello():
    return "Hello from a dependency!"

# Step 2: Inject it using Depends
@app.get("/")
def read_root(greeting: str = Depends(say_hello)):
    return {"message": greeting}



  🖥️ Start the FastAPI server:
uvicorn di_app:app --host 0.0.0.0 --reload --port 9005
✅ Try it — FastAPI will automatically call  and inject its return value.


  🔐 Add Security – API Key Validation
Let’s say every route must check if a valid API key is present in the request headers.We can use FastAPI’s  along with  to inject and validate the API key for any endpoint.Here's how you define a reusable  to validate the API key:from fastapi import Header, HTTPException

API_KEY = "mysecret"

def verify_api_key(x_api_key: str = Header(...)):
    if x_api_key != API_KEY:
        raise HTTPException(status_code=401, detail="Invalid API Key")

@app.get("/secure")
def secure_data(_ = Depends(verify_api_key)):
    return {"data": "Top secret info!"}



  🖥️ Start the FastAPI server:
uvicorn di_app:app --host 0.0.0.0 --reload --port 9005



  🔄 Reusable Pagination Logic
Sometimes, you want to apply the same pagination logic to multiple endpoints (e.g.,  and  query parameters).Instead of repeating the parameters in every route, you can use  to inject reusable logic — keeping your code clean and DRY.


  ✅ Define a Reusable Pagination Dependency
from fastapi import Depends, FastAPI

app = FastAPI()

def pagination(skip: int = 0, limit: int = 10):
    return {"skip": skip, "limit": limit}

@app.get("/items")
def get_items(paging: dict = Depends(pagination)):
    return {"pagination": paging}

 is a simple function that takes  and  as  with default values. injects those values into your route as a .You can reuse  in  that supports pagination — no duplication!


  🖥️ Start the FastAPI server:
uvicorn di_app:app --host 0.0.0.0 --reload --port 9005
This pattern is perfect for **list-based APIs like , , , and more — where consistent pagination behavior is needed.**Inject shared logic (API key, DB session, etc.)Use  +  for auth checksQuery params as dependenciesReuse pagination, filtering, etc. in multiple routesDependency Function ExampleReuse  and  parametersInject DB connection using SQLAlchemyGet current user from JWT or sessionHey there! I’m , an AWS Community Builder and passionate cloud-native enthusiast who loves building scalable backend systems and sharing knowledge with the community.


  💬 Share Your Thoughts – I'd Love Your Feedback!
If you enjoyed today's post or learned something new, I'd truly appreciate it if you leave a comment or share your thoughts 👇Your feedback, questions, or even a quick  keeps me motivated to continue this journey and share more in the upcoming  posts.✅ What did you find most helpful?Anything you'd like explained in the next part?Suggestions for improvement? I’m all ears! 🙌Let’s grow and learn together — one FastAPI day at a time 🚀

When building a command line application (CLI), developers use CLI Option Prompt [typer]. However, if you need more interactivity and simplicity on the terminal, you are likely to use . Like every library in development, we have to pause and consider: How much control are we really giving up when we depend on typer.prompt() to make our CLI more interactive?I have been building a CLI application to better track and predict cervical cancer in women. The Typer library was great in creating visually-appealing output on the terminal, until I needed to enable a filtering option. I wanted to give my user the option of filtering health profiles based on a single ID or leave blank to provide an unfiltered output. However, in my testing, I realized that by pressing ENTER without inputting any value, typer.prompt() re-prompted me to input a value, instead of accepting an empty string. I got into a loop of prompts.Despite expecting user_id to be "", the prompt came up again!As usual, I thought that my logic was wrong, so I went back different 'best practices' in CLI:I began by guarding user_id by changing from: user_id = typer.prompt("Filter by user ID (or leave blank)").strip() or None list_all_profiles(user_id=int(user_id) if user_id else None)
user_input = typer.prompt("Filter by user ID (or leave blank)").strip() user_id = int(user_input) if user_input else None list_all_profiles(user_id=user_id) After option 1 failed, I tried added isdigit() to eliminate catch non-numeric issues, but that failed, and the loop continued. Next, I wrapped the code in a try-except block with return values to prevent re-looping due to unexpected errors and value-errors, but I kept incurring an endless loop of re-prompting. Until I came across an 8-year old Stack Overflow issue [Stack Overflow] about Python's Click limit with empty prompts. While the issue had Click's syntax, I decided to replicate it on typer.prompt:elif choice == '2': try: typer.secho("Leave filters blank to view all profiles.", fg=typer.colors.BRIGHT_BLACK)
user_input = typer.prompt("Filter by user ID (or leave blank)", default="").strip() user_id = int(user_input) if user_input else None list_all_profiles(user_id=user_id)
except ValueError: typer.secho("Invalid filter values. Please use numbers or leave blank.", fg=typer.colors.RED)
except Exception as e: typer.secho(f"Unexpected error: {e}", fg=typer.colors.RED)
Although this Prompt behavior in Typer is logical once comprehended, it is not obvious, especially for beginners. Therefore, the Prompt's interactivity would improve by:Typer providing advanced documentation on prompt() behavior in different scenarios.Providing alternatives, especially when defaults are not set. Clear warnings or handling of empty inputs in CLIs. Are you exploring CLIs and Typer? Have you ran into this challenge and have ways of enhancing prompt()? Consider visiting and contributing to their GitHub repository [fastApi/typer].Like any other bug, this prompt() problem reminded me of how all libraries have simple tools that while they simplify our codes, they demand an understanding of underlying principles.I hope my journey with Typer and empty inputs saves someone and builds to the tool's best practices.

Welcome to of our FastAPI journey! Yesterday, we explored how to use to handle dynamic URLs.Today, we’re entering the world of and — the backbone of data validation in FastAPI.
🧠 Why Do We Need Request Bodies? Let’s imagine you're building an online registration form for a new user. You need details like name, email, and age. These details are not passed in the URL but rather sent in the .This is where and come into play in FastAPI.
🧩 Real-World Analogy: Pydantic is the Bouncer at a Club Think of your API like a nightclub. You can’t just let anyone in. The bouncer at the door checks if you're:On the list (valid email)Actually a real person (non-empty name)Just like that, is your API’s gatekeeper — it checks if the incoming request body has the correct structure and data types.
🔧 Step-by-Step: Create a POST Endpoint We'll create a FastAPI app that accepts a JSON body with user details.
📁 Create a file called : from fastapi import FastAPI from pydantic import BaseModel
app = FastAPI()
# 🎯 Step 1: Define your request body schema using Pydantic class User(BaseModel): name: str email: str age: int
# 🎯 Step 2: Create a POST endpoint to accept the request body @app.post("/user") def create_user(user: User): return { "message": f"Welcome, {user.name}!", "email": user.email, "age": user.age }
🖥️ Start the FastAPI server: uvicorn user:app --host 0.0.0.0 --port 9002 --reload 📤 Try sending this sample JSON:{ "name": "Utkarsh", "email": "utkarsh@example.com", "age": 28 } ✅ FastAPI will automatically validate the request and return a structured response or helpful error messages.
🧪 Add Validation with Pydantic Let’s enhance the model with proper validation using , default values, and field constraints.
🔧 Prerequisite: Install To use for validating emails, you must install the package.Run this command in your terminal:pip install pydantic[email]
🔧 Step-by-Step: Create a POST Endpoint We'll create a FastAPI app that accepts a JSON body with user details.
📁 Create a file called : from fastapi import FastAPI from pydantic import BaseModel, EmailStr, Field from typing import Optional
app = FastAPI()
class User(BaseModel): name: str = Field(..., min_length=2, max_length=50) email: EmailStr age: Optional[int] = Field(None, ge=18, le=100)
@app.post("/user") def create_user(user: User): return { "message": f"Welcome, {user.name}!", "email": user.email, "age": user.age } : Required string with a minimum length of 2 and a maximum of 50.: Must be a valid email address ( from Pydantic).: Optional integer; if provided, it must be between 18 and 100.
🖥️ Start the FastAPI server: uvicorn user:app --host 0.0.0.0 --port 9004 --reload 📤 Try sending this sample JSON:{ "name": "Utkarsh", "email": "utkarsh@example.com", "age": 16 }
🌍 Real-World Example – Feedback API from fastapi import FastAPI from pydantic import BaseModel, EmailStr, Field
app = FastAPI()
class Feedback(BaseModel): name: str email: EmailStr message: str = Field(..., min_length=10)
@app.post("/feedback") def submit_feedback(feedback: Feedback): return { "status": "received", "from": feedback.name, "email": feedback.email } { "name": "Utkarsh", "email": "Utkarsh@email.com", "message": "Great job with the FastAPI series!" }
📦 Nested Models Example – Customer with Address from fastapi import FastAPI from pydantic import BaseModel
app = FastAPI()
class Address(BaseModel): city: str pincode: int
class Customer(BaseModel): name: str address: Address
@app.post("/customer") def create_customer(customer: Customer): return {"msg": f"{customer.name} from {customer.address.city} added."}
{ "name": "Utkarsh", "address": { "city": "Mumbai", "pincode": 110 } }
Define and validate data modelsAdd constraints like min, max, defaultModel complex JSON structuresHey there! I’m , an AWS Community Builder and passionate cloud-native enthusiast who loves building scalable backend systems and sharing knowledge with the community.
